import React from 'react';
import { Input } from '@linm-soft/common-components';
import type { MaterialDto } from '../../services/master/models';
import type { InvoiceLineDto } from '../../services/bh/models';
import { recalcInvoiceLine } from '../../utils/orderLines';
import { LineMaterialSearchCell, MaterialLineTableHeaders } from '../search/LineMaterialSearchCell';
import { MaterialLinesGridActions } from './MaterialLinesGridActions';
import df from '../../styles/documentForm.module.css';

export type InvoiceLinesGridProps = {
  lines: InvoiceLineDto[];
  canEdit: boolean;
  onChange: (lines: InvoiceLineDto[]) => void;
  onAddLine: () => void;
  onCopyLine: () => void;
  lineRowProps: (idx: number) => React.HTMLAttributes<HTMLTableRowElement>;
  onRemoveLine: (idx: number) => void;
};

export const InvoiceLinesGrid: React.FC<InvoiceLinesGridProps> = ({
  lines,
  canEdit,
  onChange,
  onAddLine,
  onCopyLine,
  lineRowProps,
  onRemoveLine,
}) => {
  const updateLine = (idx: number, patch: Partial<InvoiceLineDto>) => {
    onChange(lines.map((l, i) => (i === idx ? recalcInvoiceLine({ ...l, ...patch }) : l)));
  };

  const handleMaterialSelect = (idx: number, material: MaterialDto) => {
    updateLine(idx, {
      materialCode: material.code,
      materialName: material.name,
      unitCode: material.unitCode || lines[idx]?.unitCode || 'Cai',
    });
  };

  const handleMaterialClear = (idx: number) => {
    updateLine(idx, { materialCode: '', materialName: '' });
  };

  return (
    <>
      <div className={df.tableWrapper}>
        <table className={[df.linesTable, df.linesTableStacked].join(' ')}>
          <thead>
            <tr>
              <MaterialLineTableHeaders />
              <th className={df.thAmount}>SL</th>
              <th className={df.thAmount}>Đơn giá</th>
              <th className={df.thAmount}>% Thuế</th>
              <th className={df.thAmount}>Tiền thuế</th>
              <th className={df.thAmount}>Thành tiền</th>
              <th className={df.thDel} />
            </tr>
          </thead>
          <tbody>
            {lines.map((line, idx) => (
              <tr key={idx} {...lineRowProps(idx)}>
                <LineMaterialSearchCell
                  materialCode={line.materialCode}
                  materialName={line.materialName ?? ''}
                  disabled={!canEdit}
                  onSelect={m => handleMaterialSelect(idx, m)}
                  onClear={() => handleMaterialClear(idx)}
                />
                <td data-label="SL" className={df.tdAmount}>
                  <Input
                    type="number"
                    value={String(line.quantity)}
                    onChange={e => updateLine(idx, { quantity: Number(e.target.value) })}
                    disabled={!canEdit}
                  />
                </td>
                <td data-label="Đơn giá" className={df.tdAmount}>
                  <Input
                    type="number"
                    value={String(line.unitPrice)}
                    onChange={e => updateLine(idx, { unitPrice: Number(e.target.value) })}
                    disabled={!canEdit}
                  />
                </td>
                <td data-label="% Thuế" className={df.tdAmount}>
                  <Input
                    type="number"
                    value={String(line.taxRate)}
                    onChange={e => updateLine(idx, { taxRate: Number(e.target.value) })}
                    disabled={!canEdit}
                  />
                </td>
                <td data-label="Tiền thuế" className={df.tdAmount}>
                  {line.taxAmount.toLocaleString('vi-VN')}
                </td>
                <td data-label="Thành tiền" className={df.tdAmount}>
                  {line.amount.toLocaleString('vi-VN')}
                </td>
                <td className={df.tdDel} data-label="">
                  <button
                    type="button"
                    className={df.btnDeleteLine}
                    onClick={() => onRemoveLine(idx)}
                    title="Xóa dòng"
                    disabled={!canEdit}
                  >
                    ×
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
      <MaterialLinesGridActions
        canEdit={canEdit}
        onAddLine={onAddLine}
        onCopyLine={onCopyLine}
        linesCount={lines.length}
      />
    </>
  );
};
